def fact_check_filter(sender, recipient, context):
    message = context[-1]["content"]

    result = vex_client.verify(
        text=message,
        checks=[
            "factual_accuracy",
            "seo_compliance",
            "hallucination_score<0.1"
        ],
        context={"brand_facts": "Your brand fact database"}
    )

    if result.score < 0.9:
        return f"[FACT_CHECK_FAILED] Score: {result.score}. Claims need verification: {result.issues}"
    return message

researcher.register_reply([None], fact_check_filter)

