def token_budget_filter(sender, recipient, context):
    """Enforce token budgets and loop detection"""
    conversation = context[-10:]  # Last 10 turns
    total_tokens = sum(len(msg["content"]) for msg in conversation)

    if total_tokens > 8000:
        return "[TOKEN_LIMIT] Conversation exceeds budget. Summarize final output."

    # Detect loops
    recent_messages = [msg["content"][:50] for msg in conversation[-3:]]
    if len(set(recent_messages)) < 2:
        return "[LOOP_DETECTED] Agents repeating. Provide final answer."

    return vex_global_filter(sender, recipient, context)

